sub_queries.sql:
SELECT Nationality, MAX(CAST(No_of_times_broken AS REAL)) AS Max_No_of_times_broken
FROM T24
GROUP BY Nationality;

SELECT Year, Time, Athlete 
FROM T34 
ORDER BY Year;

SELECT Time, Athlete, Location FROM T22
UNION
SELECT Time, Athlete, Location FROM T23;

SELECT MIN(Year) AS Min_Year, MAX(Year) AS Max_Year
FROM (
  SELECT Year FROM T22
  UNION ALL
  SELECT Year FROM T23
);

SELECT Nationality, COUNT(*) AS Count
FROM T24
GROUP BY Nationality;

SELECT Nationality, COUNT(*) AS count
FROM T24
GROUP BY Nationality;

SELECT MIN(Year) AS Min_Year, MAX(Year) AS Max_Year
FROM (
  SELECT Year FROM T22
  UNION ALL
  SELECT Year FROM T23
);

SELECT Nationality, SUM(CAST(No_of_times_broken AS INTEGER)) AS Total_times_broken
FROM T24
GROUP BY Nationality;

SELECT Location 
FROM T22 
WHERE Time = (SELECT MIN(Time) FROM T22);

SELECT MIN(Year) AS Earliest_Year, MAX(Year) AS Latest_Year
FROM (
  SELECT Year FROM T22
  UNION ALL
  SELECT Year FROM T23
);

SELECT Athlete, Location, MIN(CAST(Time AS REAL)) AS Fastest_Time
FROM T34
GROUP BY Athlete, Location;

SELECT DISTINCT Athlete FROM T34
UNION
SELECT DISTINCT Athlete FROM T54;

SELECT Year, Time, Athlete 
FROM T34 
ORDER BY Year;
